// ─── Types ───────────────────────────────────────────────────────────────────

/** Body area codes used across the library */
export type BodyArea = 'LB' | 'UB' | 'NK' | 'SH' | 'WR' | 'HI' | 'KN' | 'AN';

/** The 8 canonical movement categories from the VINYS taxonomy */
export type MovementCategory =
  | 'Spinal Mobility'
  | 'Stability / Core'
  | 'Hip Mobility'
  | 'Balance'
  | 'Upper Limb Weight Bearing'
  | 'Restorative'
  | 'Breath'
  | 'Transitional';

/** Normalized movement direction tags used by Engine 2 diversity rules */
export type MovementDirection =
  | 'Flexion'
  | 'Extension'
  | 'Flexion–Extension Cycle'
  | 'Rotation'
  | 'Lateral Flexion'
  | 'Neutral Stability'
  | 'Multi-plane';

/** Stability level — supports Engine 3 phase placement */
export type StabilityLevel = 'low' | 'medium' | 'high';

/**
 * Per-area clinical profile data.
 * Profile codes vary by area (e.g. LB uses FL/EX/NE/LI/ST, HI uses AN/LA/PO/MO/ST/NE).
 */
export interface AreaProfile {
  /** Profile codes that score +2 for this exercise in this area */
  especially_beneficial: string[];
  /** Profile codes that score -1 (exercise is usable with modification) */
  caution: string[];
  /** Profile codes that hard-exclude this exercise for this area */
  avoid: string[];
  /** Modification instruction for caution profiles (free text) */
  modifications: string;
}

/** Complete exercise entry matching Aviv\'s Algorithm Specification v1.0 */
export interface Exercise {
  /** Stable unique ID */
  id: string;
  /** English display name (e.g. "Tabletop — Classic") */
  name: string;
  /** Base pose family for diversity rule (e.g. "Tabletop", "Warrior") */
  pose_family: string;
  /** Body areas this exercise loads — used for max_same_body_area rule */
  areas: BodyArea[];
  /** Primary movement function — main diversity filter */
  movement_category: MovementCategory;
  /** Normalized movement direction — used for max_same_movement_dir rule */
  movement_direction: MovementDirection;
  /** Load type — supports E3 sequencing (passive early, dynamic late) */
  load_type: string;
  /** Stability demand — supports E3 phase complexity filter */
  stability: StabilityLevel;
  /**
   * Coordination demand 1–4.
   * 1 = simple/passive · 2 = gentle active · 3 = standard · 4 = complex
   * Used as E3 complexity filter: Arrival/Closure max 1, Build max 3, Peak max 4
   */
  complexity: 1 | 2 | 3 | 4;
  /** Functional goals (e.g. Motor Control, Mobility, Proprioception) */
  goal_tag: string[];
  /**
   * Load proxy for session building. Range: 1 (most accessible) → 6+ (peak demand).
   * null for PT exercises (adjustable per session).
   * Drives E3 phase placement:
   *   1 → Arrival/Closure · 2 → Preparation · 3 → Early Build
   *   4 → Main Build · 5 → Pre-Peak · 6+ → Peak
   */
  var_rank: number | null;
  /** Duration range in seconds [min, max] */
  duration: [number, number];
  /** Name of a simpler alternative pose for E2 substitution triggers */
  simpler_alternative: string | null;
  /** Per-area clinical profile data (Especially Beneficial / Caution / Avoid) */
  profiles: Partial<Record<BodyArea, AreaProfile>>;
  /** Clinical rationale — for human review, not used computationally */
  clinical_rationale: string;
  /** Video file ID — null until video production delivers */
  video_id: string | null;
}

