// ─── Helper: find exercise by name (case-insensitive, partial match) ──────────
export function findExercise(name: string): Exercise | undefined {
  const low = name.toLowerCase().trim();
  return EXERCISES_V2.find(
    e => e.name.toLowerCase() === low ||
         e.name.toLowerCase().includes(low) ||
         low.includes(e.pose_family.toLowerCase())
  );
}

// ─── Helper: get exercises by category ───────────────────────────────────────
export function getByCategory(cat: MovementCategory): Exercise[] {
  return EXERCISES_V2.filter(e => e.movement_category === cat);
}

// ─── Helper: get exercises by var rank range ──────────────────────────────────
export function getByVarRank(min: number, max: number): Exercise[] {
  return EXERCISES_V2.filter(e => e.var_rank !== null && e.var_rank >= min && e.var_rank <= max);
}

// ─── Derived stats ─────────────────────────────────────────────────────────────
export const LIBRARY_STATS = {
  total: EXERCISES_V2.length,
  by_category: Object.fromEntries(
    ['Spinal Mobility', 'Stability / Core', 'Hip Mobility', 'Balance',
     'Upper Limb Weight Bearing', 'Restorative', 'Breath', 'Transitional'].map(cat => [
      cat, EXERCISES_V2.filter(e => e.movement_category === cat).length
    ])
  ),
} as const;
